// Validate required intake fields
const input = $input.first().json;
const errors = [];

if (!input.contact?.first_name) errors.push('Missing first_name');
if (!input.contact?.last_name) errors.push('Missing last_name');
if (!input.contact?.email && !input.contact?.phone) errors.push('Missing email and phone — need at least one');
if (!input.case_info?.type) errors.push('Missing case type');
if (!input.case_info?.description) errors.push('Missing case description');

// Normalize phone to E.164 if present
let phone = input.contact?.phone || '';
if (phone && !phone.startsWith('+')) {
  phone = '+1' + phone.replace(/\D/g, '');
}

// Strip nulls/empty strings
const cleanContact = Object.fromEntries(
  Object.entries(input.contact || {}).filter(([_, v]) => v != null && v !== '')
);

return [{
  json: {
    valid: errors.length === 0,
    errors,
    contact: { ...cleanContact, phone },
    case_info: input.case_info,
    source: input.source || 'unknown',
    referral_source: input.referral_source || 'unknown',
    timestamp: input.timestamp || new Date().toISOString(),
    firm: 'Greenfield & Associates'
  }
}];

// Parse AI classification and merge with intake data
const intake = $('Check Duplicates — Airtable').first().json;
const aiResponse = $input.first().json;

let classification;
try {
  const content = aiResponse.choices?.[0]?.message?.content || '{}';
  classification = JSON.parse(content);
} catch (e) {
  classification = { case_type: 'other', confidence: 0, urgency: 'standard', summary: 'AI classification failed — manual review required' };
}

return [{
  json: {
    ...intake,
    ai_classification: classification,
    requires_human_review: true,
    review_status: 'pending',
    review_reason: classification.confidence < 0.8 ? 'low_confidence' : 'standard_gate'
  }
}];
